            const double B1 = (1.0 - x) * 0.5 / sh_sc[1] + B0;
            const double B1p = (1.0 - x) * 0.5 / sh_sc[2] + B0;

            const double Cx_ = (sh_sc[3] - Ax) + (sh_sc[2] * inv_denom) * x * (sh_sc[6] - sh_sc[3]);
